def instagram_lesson() -> Lesson:
    return Lesson(id="hld-instagram", number=216, title="Instagram (Photo Sharing)",
        focus=("photo storage","CDN caching","feed generation","hybrid timeline","read-heavy"),
        overview="Design a highly available, read-heavy photo and video sharing platform like Instagram.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("ins-1","How does Instagram scale photo and video delivery globally to hundreds of millions of active readers?","medium",("case-study",),
             ("By forcing clients to download photos directly from other online users' devices via P2P", "By routing all active traffic through a single massive database master node", "By saving raw image binary data directly inside relational database tables", "By storing optimized media files in cloud object storage (S3) and caching them globally at CDN edge nodes"),3,
             "CDNs serve static photos and videos from edge servers close to the user, bypassing origin servers and ensuring fast, low-latency reads."),
        quiz("ins-2","What image processing steps are required when a user uploads a high-resolution photo?","medium",("case-study",),
             ("Encrypt the image binary data using high-ratio symmetric algorithms", "Convert the photo into a Base58 string array and index it inside a relational table", "Validate the picture by fanning it out to all followers for manual approval", "Resize to multiple standard device resolutions, compress to web-friendly formats, generate thumbnails, and upload to storage"),3,
             "Image processing optimizes delivery: serving lightweight thumbnails for feeds and high-res versions only when clicked saves bandwidth."),
        quiz("ins-3","Why is a hybrid feed model (Push + Pull) preferred over pure Push for Instagram feeds?","hard",("case-study",),
             ("Pure Push requires using symmetric encryption keys for every single activity summary", "It prevents users from editing their post captions after uploading", "Pure Push works only on iOS devices; pull is designed exclusively for Android systems", "Pure Push (Fan-out on Write) breaks when a celebrity posts, triggering millions of concurrent feed writes (celebrity problem)"),3,
             "Celebrity accounts have millions of followers. Pushing posts to all follower lists instantly saturates cache databases. Use hybrid pull instead."),
        quiz("ins-4","How does a hybrid feed architecture handle feed generation on Instagram?","hard",("case-study",),
             ("Force all users to use the pull model during peak hours, and push only during low traffic", "Convert all celebrity feeds into static PDF files distributed via CDN", "Pre-compute feeds for regular accounts (Push); dynamically merge posts from followed celebrities (Pull) when the user loads their feed", "Store celebrity posts in a separate relational database that uses vertical scaling only"),2,
             "Hybrid: pre-compute feeds from regular users (push). When rendering, query celebrity posts dynamically (pull) and merge them."),
        quiz("ins-5","Which technology is best suited for storing and serving pre-computed news feeds?","medium",("case-study",),
             ("An append-only log file stored on a shared network drive", "An in-memory store like Redis, representing timelines as Sorted Sets (ZSET) ordered by timestamp", "A distributed graph database containing all historical post comments", "A relational database with complex multi-table JOINs on every page load"),1,
             "Redis Sorted Sets keep timelines pre-sorted by post ID/timestamp. Fetching a page is a fast O(log N + M) memory operation."),
        quiz("ins-6","How do you limit the storage footprint of pre-computed feeds in Redis?","medium",("case-study",),
             ("Store only the user's primary key in Redis and fetch everything else from relational tables", "Only cache the feed timeline for active users (e.g., accessed in the last 30 days) and cap feed sizes (e.g., max 500 items)", "Compress all text characters into binary representations using Huffman coding", "Delete all user posts that are older than 24 hours automatically"),1,
             "Capping the timeline size (e.g., top 500 items) and evicting inactive users prevents memory bloat while preserving fast read speeds."),
        quiz("ins-7","What is the role of the Fan-out Service in Instagram's upload pipeline?","medium",("case-study",),
             ("To parse post text for full-text search indexing in Elasticsearch", "To balance HTTP requests across the frontend web servers", "To encrypt post content before it is written to the database", "To consume post events from a message queue and distribute them to followers' timelines asynchronously"),3,
             "The fan-out service runs in the background (off the main write path), ensuring post distribution does not slow down the creator's post confirmation."),
        quiz("ins-8","How are posts and user profile details best cached?","easy",("case-study",),
             ("Query the database primary write replica on every single user view page click", "Write the problem description to a shared file system mounting drive", "Force user browsers to store all problem descriptions permanently in their local filesystem", "Cache post metadata in a distributed Redis store using the Cache-Aside pattern (key is post_id)"),3,
             "Post metadata (caption, tags, author ID) is highly static. Caching it in Redis avoids expensive DB queries during feed loading."),
        quiz("ins-9","Why is standard relational database pagination (OFFSET) bad for infinite scroll feeds?","hard",("case-study",),
             ("Relational databases do not support page-based offset SQL statements", "OFFSET forces the client browser to reload all CSS styling files", "It locks the entire database table during query execution", "If new posts are added at the top, the window shifts, causing duplicate or skipped items on subsequent pages"),3,
             "New posts shift row indices. Use cursor-based pagination (e.g. WHERE id < last_seen_id LIMIT 10) for stable feeds."),
        quiz("ins-10","How should like counts and comment counts be tracked in the feed efficiently?","hard",("case-study",),
             ("Force users to wait for database locks to release before casting a like", "Write like events to client browser local storage only", "Run a full COUNT(*) query across the entire comments and likes table on every post load", "Store counters in a fast in-memory cache (Redis) and periodically batch-update the relational database"),3,
             "Aggregating counts in memory prevents database write bottlenecks on viral posts where thousands of users 'like' simultaneously."),
        quiz("ins-11","How does the system handle real-time activity feed notifications (e.g., 'A followed you' bubble)?","medium",("case-study",),
             ("Push notifications via WebSockets, SSE, or mobile push services (APNs/FCM) managed by a notification service", "Send a background SMS ping to the user's phone on every new follower", "Force the client browser to refresh the entire page every 5 seconds", "Scan the relational database constantly using recursive client-side queries"),0,
             "Real-time notifications are pushed asynchronously via persistent connections, keeping the feed interactive with zero read lag."),
        quiz("ins-12","What type of index optimizes looking up all posts for a specific hashtag?","hard",("case-study",),
             ("A GIN index built on the programming language string", "A single index on the post text hash", "A clustered index sorting all submissions by date only", "An inverted index built on the tags array field or a GIN index in PostgreSQL"),3,
             "Inverted and GIN indexes allow near-instant exact match lookups for list elements like hashtags."),
        quiz("ins-13","What is the advantage of using a NoSQL Document Store (like MongoDB) for post metadata storage?","medium",("case-study",),
             ("Posts have varying attributes (filters, locations, tags, media types) that fit well in document schemas, and scale horizontally", "It automatically prevents duplicate posts through hardware-level validation", "NoSQL databases natively support ACID transactions across multiple unrelated tables", "It eliminates the need for any server-side validation logic"),0,
             "Document stores match the highly variable schema of media posts, allowing flexible properties storage without schema migrations."),
        quiz("ins-14","What type of index optimizes looking up all posts for a user sorted by creation date?","easy",("case-study",),
             ("A partial index built only on the posts that contain media assets", "A single index on the post caption text string", "A composite index on (user_id, created_at DESC)", "A hash index built on the profile picture URL"),2,
             "Composite index on (user_id, created_at DESC) allows instant, pre-sorted retrieval of a user's history for their profile timeline."),
        quiz("ins-15","What is the role of a Message Queue (e.g., Kafka) in the post writing pipeline?","medium",("case-study",),
             ("To encrypt message packets before transmitting them to databases", "To buffer newly created posts and decouple the write API from the asynchronous fan-out worker pool", "To balance HTTP connections across frontend reverse proxies", "To store historical post comments for fast lookup search indexes"),1,
             "Kafka absorbs write spikes, guarantees message delivery, and allows fan-out workers to process distribution lists at their own pace."),
        quiz("ins-16","How does Instagram prevent 'thundering herd' spikes when a highly popular post is viewed concurrently by millions?","medium",("case-study",),
             ("Route all queries through a single thread to guarantee chronological ordering", "Disable CSS and Javascript styling to reduce network traffic", "Use single-flight cache design to ensure only one database query is executed on a cache miss, while other requests wait", "Directly increase database write locks to block non-contest traffic"),2,
             "Mutex locks inside the application layer prevent redundant concurrent database calls from executing for the same expired cache key."),
        quiz("ins-17","What is the primary trade-off of storing pre-computed feeds in Redis vs a NoSQL Document Store?","medium",("case-study",),
             ("Redis is strongly consistent; Document stores are always eventually consistent", "Redis provides ultra-low latency in RAM but is highly expensive; Document stores are cheaper (disk-based) but slower", "Redis only supports text storage; Document stores can store raw binary video files natively", "Redis requires custom database hardware; Document stores run on standard cloud VMs"),1,
             "RAM storage (Redis) is fast but costly. Storing older feeds or inactive timelines on disk (e.g. Cassandra/Mongo) keeps costs sane."),
        quiz("ins-18","How does Instagram secure private posts (blocking posts from private accounts you don't follow)?","hard",("case-study",),
             ("Enforce strict permission checks in the Feed API layer, validating relationships in a fast graph cache before rendering", "Allow all posts in the feed but obscure the text using CSS styling for unauthorized users", "Encrypt posts from private accounts with a master key that is blocked by local client firewalls", "Store private posts in separate physical databases located in different countries"),0,
             "Timelines can get stale. A final security filter at the API layer ensures no private content leaks if relationship statuses change."),
        quiz("ins-19","What type of locking is most appropriate when updating user profile details?","medium",("case-study",),
             ("Optimistic locking (version numbers) since profile updates are infrequent and have very low contention", "Pessimistic locking (SELECT FOR UPDATE) to block all reads during the update phase", "Enforcing a database-wide table lock on the user table", "Distributed Redlock across all active global application servers"),0,
             "Profiles are rarely updated by multiple actors. Optimistic locking avoids the performance overhead and deadlocks of pessimistic locks."),
        quiz("ins-20","What index optimizes fetching a user's own posts for their personal profile timeline?","easy",("case-study",),
             ("A single index on the post content text string", "A partial index built only on the posts that contain media assets", "A composite index on (user_id, created_at DESC)", "A hash index covering the profile picture URL"),2,
             "Composite index on (user_id, created_at DESC) allows instant, pre-sorted retrieval of a user's history for their profile timeline."),
    ))

def youtube_top_k_lesson() -> Lesson:
    return Lesson(id="hld-youtube-top-k", number=217, title="YouTube Top K",
        focus=("heavy analytics","count-min sketch","mapreduce","flink streaming","sliding window"),
        overview="Design a real-time analytics system to compute the 'Top K' most viewed videos on YouTube.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("ytk-1","What is the primary challenge of computing the absolute Top 100 most viewed videos in real-time on YouTube?","medium",("case-study",),
             ("Relational databases lack mathematical algorithms to calculate the highest numbers", "Computing Top K requires pausing all live streams globally to run counting loops", "The massive scale of events (millions of views/sec) makes it impossible to maintain exact, synchronized counters in a single database", "Video IDs are too long to fit in standard in-memory caches"),2,
             "Ingesting every view event to update a central exact counter creates a severe database write hotspot and processing bottleneck."),
        quiz("ytk-2","What data structure provides approximate high-frequency event counts with a tiny, fixed memory footprint?","hard",("case-study",),
             ("A distributed relational database view with heavy indexing columns", "Count-Min Sketch (a probabilistic data structure using multiple hash functions and a 2D counter array)", "A global consistent-hashing ring containing all historical video IDs", "An append-only flat log file stored on a shared network drive"),1,
             "Count-Min Sketch estimates event frequencies using a fixed memory layout, offering O(1) update and lookup with bounded error."),
        quiz("ytk-3","How does the Count-Min Sketch estimate the frequency of a video ID?","hard",("case-study",),
             ("Run a mathematical average across all counters in the array", "Take the sum of all counter fields matched by the hashes", "Hash the ID using N different hash functions, locate the counters, and return the minimum value (to minimize hash collisions)", "Retrieve the last written counter from the primary database shard"),2,
             "Using the minimum value from the hashed counter slots avoids overestimation errors caused by hash collisions."),
        quiz("ytk-4","What technology is best suited for real-time windowed event processing (e.g. tracking views in the last 1 minute)?","medium",("case-study",),
             ("Running a Cron job that executes SQL COUNT queries on a relational database every 60 seconds", "A distributed locking service (like ZooKeeper) coordinating write replicas", "A stream processing engine like Apache Flink or Apache Spark Streaming", "Storing view events in client browser local cookies and merging them"),2,
             "Flink excels at stateful stream computations over sliding windows, aggregating view counts in memory as events pass by."),
        quiz("ytk-5","How can we implement a hybrid model that provides 100% exact counts for cold videos and approximate counts for hot ones?","hard",("case-study",),
             ("Disable real-time tracking for cold videos completely", "Require all viewers to complete CAPTCHA screens before updating exact counts", "Store all video counts in Redis, and reboot the cluster every hour to wipe inactive keys", "Filter views: route high-volume hot video IDs to a Count-Min Sketch, and cold video IDs to a transactional database counter"),3,
             "A hybrid model handles data skew: heavy-hitters go through high-throughput streaming caches; sparse long-tail items update a relational DB safely."),
        quiz("ytk-6","What is the role of a 'Heavy Hitter' detector (e.g. Lossy Counting) in Top K analytics?","hard",("case-study",),
             ("To balance HTTP gateway requests across distributed reverse proxies", "To identify and keep a precise, in-memory list of the top candidates (e.g., using a Min-Heap) while discarding low-frequency keys", "To verify that coordinates do not contain non-numeric characters", "To encrypt transaction payloads during billing calculations"),1,
             "A Min-Heap tracks the active Top K. When a key's estimated count exceeds the heap's minimum, it replaces the min, keeping the ranking current."),
        quiz("ytk-7","Why is sharding view event data by Video ID highly beneficial for Top K streaming aggregators?","hard",("case-study",),
             ("It eliminates the need for maintaining Redis memory keys for rate limiting", "It automatically encrypts video titles using distributed symmetric keys", "It ensures all view events for a specific video route to the exact same streaming node, allowing highly efficient local aggregation", "It distributes the exact same event across all physical nodes in parallel"),2,
             "Routing events by Video ID (key-by) means each Flink/Spark worker aggregates its subset locally in memory, preventing network bottlenecking."),
        quiz("ytk-8","What is the 'thundering herd' issue in a distributed analytical counter, and how is it avoided?","hard",("case-study",),
             ("When multiple gateways attempt to write to the same Redis master node concurrently, causing CPU spikes", "When client devices reboot repeatedly to bypass rate limit checks", "When a global window resets, millions of aggregate writes hit the database simultaneously, causing CPU spikes", "When Redis replication lag causes different gateways to see contradictory rate limit status logs"),2,
             "Reset bursts are mitigated by using jitter (randomizing limit windows), sliding windows (which don't reset all at once), or queues."),
        quiz("ytk-9","How does a MapReduce job help in calculating the Top K videos?","medium",("case-study",),
             ("MapReduce automatically compiles video streaming code files", "MapReduce encrypts the raw video files before storage", "MapReduce runs daily or hourly batch jobs to calculate exact, consolidated historical rankings over raw log files on HDFS/S3", "MapReduce handles real-time WebSocket connection state routing"),2,
             "While streaming engines give near-real-time estimates, MapReduce batch runs guarantee 100% accurate, deep-history consolidated rankings."),
        quiz("ytk-10","Why are in-memory Redis Sorted Sets (ZSET) excellent for serving the active Top K list to users?","medium",("case-study",),
             ("They keep the Top K elements pre-sorted by view count, enabling ultra-fast, low-latency O(1) reads of the top list", "They eliminate the need for maintaining relational database backups", "They automatically compress the video descriptions to save RAM", "They can be hosted inside the client's local smartphone OS environment"),0,
             "A ZSET containing the active top 100 video IDs is extremely fast to read (ZRANGE), serving millions of daily hits with near-zero latency."),
        quiz("ytk-11","What is the primary drawback of using a simple, single Redis counter (INCR) for every video view?","hard",("case-study",),
             ("INCR commands require complex relational database table locks", "A viral video (e.g. 100,000 views/sec) will saturate the single Redis key, creating severe lock contention and network hotspots", "Redis automatically deletes counter keys after 24 hours of inactivity", "Redis counters are restricted to values under 1,000"),1,
             "Hotspotting: high-frequency writes to a single Redis key overwhelm the single Redis thread. Solve via write-batching on web servers first."),
        quiz("ytk-12","How does 'Write Batching' (buffered counters) on application servers protect Redis?","medium",("case-study",),
             ("Web servers increment local in-memory counters, flushing them to Redis in batches (e.g. every 1 second or 1,000 views)", "It automatically encrypts the counter variables", "It forces all users to wait for database locks to release before casting a like", "It writes view logs to client browser local storage only"),0,
             "Batching aggregates views locally first (1000 pings -> 1 write of +1000), reducing write calls to Redis by 99.9% during viral peaks."),
        quiz("ytk-13","What type of sliding window is best for a 'Trending Now' feed (updating every 10 seconds with the last 1 hour of data)?","hard",("case-study",),
             ("A sliding window with a length of 1 hour and a slide interval of 10 seconds", "A global window that accumulates data indefinitely without eviction", "A tumbling window that resets completely every 1 hour", "A session window that closes only when user activity stops"),0,
             "Sliding windows overlap: they compute the last hour's trends and refresh the results every 10 seconds to keep the feed highly fresh."),
        quiz("ytk-14","What is the benefit of a HyperLogLog data structure in YouTube analytics?","hard",("case-study",),
             ("It replaces the database for storing raw video files", "It encrypts user viewer histories for security compliance", "It automatically routes client requests to the nearest server", "It estimates the number of unique viewers (cardinality) for a video with near-perfect accuracy using negligible, fixed memory (12KB)"),3,
             "HyperLogLog estimates unique counts (e.g. daily active viewers on a video) using fixed memory, avoiding storing massive sets of user IDs."),
        quiz("ytk-15","How do you handle 'late-arriving data' (events delayed due to client offline states) in streaming engines?","hard",("case-study",),
             ("Discarding all delayed events automatically to prevent out-of-order errors", "Using Watermarks, which tell the window processing engine when to close and evaluate a time window despite missing events", "Forcing all client devices to maintain a constant synchronized internet connection", "Rebooting the streaming cluster whenever delayed events are detected"),1,
             "Watermarks track event-time progress. A watermark of T allows the system to process events up to time T, ignoring or logging late-arrivers."),
        quiz("ytk-16","What index optimizes looking up historical trending lists by date?","easy",("case-study",),
             ("A single index on the video title text string", "A partial index built only on videos containing ads", "A hash index built on the channel name", "A composite index on (trending_date, view_count DESC)"),3,
             "A composite index on (trending_date, view_count DESC) allows the database to instantly retrieve pre-sorted trending lists for any historical date."),
        quiz("ytk-17","What is the role of the Event Broker (e.g. Kafka) in YouTube's Top K pipeline?","medium",("case-study",),
             ("To write event logs to the client's phone filesystem", "To encrypt video streaming files during transport layer security (TLS) handshakes", "To ingest millions of raw view events, decouple them from backend processing, and serve as the immutable log for analytics streams", "To balance HTTP connections across frontend reverse proxies"),2,
             "Kafka acts as the high-throughput buffer, allowing Flink, Spark, and MapReduce jobs to read view events concurrently without losing data."),
        quiz("ytk-18","How can the system identify click-bait views or artificial bot inflation?","medium",("case-study",),
             ("Enforcing a strict limit of one view per user per video per lifetime", "Deleting the video if it accumulates more than 1M views in an hour", "Requiring every viewer to solve a CAPTCHA puzzle before watching a video", "Asynchronously analyzing view patterns, watch durations, IP networks, and account history to filter out fraudulent events"),3,
             "An analytical spam pipeline runs out-of-band to flag and deduct bot views, ensuring trending lists represent real human engagement."),
        quiz("ytk-19","What is the primary trade-off of a probabilistic data structure (like Count-Min Sketch) in analytics?","medium",("case-study",),
             ("It prevents athletes from editing their activity titles after posting", "It works only on mobile device frameworks, not desktop web browsers", "It requires using symmetric encryption keys for every single query summary", "It saves massive RAM and CPU but introduces a small probability of overestimation (due to hash collisions)"),3,
             "Probabilistic structures sacrifice exact precision for extreme scale. For Top K trending lists, small estimation errors are perfectly acceptable."),
        quiz("ytk-20","What index optimizes looking up all view events for a video inside a specific hour?","hard",("case-study",),
             ("A single index on the user's password hash column", "A hash index built on the channel name", "A composite index on (video_id, view_time)", "A partial index built only on videos containing ads"),2,
             "A composite index on (video_id, view_time) allows the analytics engine to fetch and count the video's views within a specific hour instantly."),
    ))

def uber_lesson() -> Lesson:
    return Lesson(id="hld-uber", number=218, title="Uber (Ride Hailing)",
        focus=("quadtree","spatial index","driver routing","order state machine","geohash"),
        overview="Design a high-performance, real-time spatial ride-hailing service like Uber or Lyft.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("ubr-1","Which coordinate indexing system is best for searching nearby restaurants or drivers in real-time?","medium",("case-study",),
             ("Standard B-tree indexes on two columns: latitude and longitude", "Geohash or Quadtree indexes to group coordinates into 2D spaces", "Sharding the database tables based on restaurant name strings", "A centralized relational database view that runs the Haversine formula on every request"),1,
             "Standard B-trees cannot query two dimensions efficiently. Geohashes or Quadtrees index 2D locations into a single dimension."),
        quiz("ubr-2","How does a Quadtree index handle highly dense areas like downtown Manhattan?","hard",("case-study",),
             ("By dropping the precision of latitude/longitude records to save memory", "By rejecting new points of interest once a node capacity limit is reached", "By recursively splitting overcrowded nodes into 4 child sub-quadrants", "By shifting coordinate data to adjacent lower-density nodes"),2,
             "Quadtrees dynamically subdivide regions into four sub-quadrants when the number of points in a cell exceeds a threshold."),
        quiz("ubr-3","What is a major limitation of a static in-memory Quadtree for dynamic driver location tracking?","hard",("case-study",),
             ("Drivers move continuously, making constant tree rebalancing and lock contention highly expensive",
              "Quadtrees cannot be loaded into server RAM structures",
              "Static trees cannot support more than 100 concurrent coordinate points",
              "Quadtrees are incompatible with modern GPS device coordinate updates"),0,
             "Rebalancing quadtrees continuously for fast-moving drivers is too slow. Better to use Redis Geospatial (Geohash-based) for drivers."),
        quiz("ubr-4","How does a geohash represent a location?","medium",("case-study",),
             ("A coordinate pair formatted as JSON arrays", "An encrypted key containing the user's physical IP address", "A 64-bit integer representing the distance from the Greenwich meridian", "A base32 string representing a specific rectangular grid cell on Earth"),3,
             "Geohash converts 2D coordinates into a single base32 string. Longer strings represent smaller, more precise grid squares."),
        quiz("ubr-5","How should the Order Status workflow be managed to avoid race conditions (e.g. multiple drivers accepting)?","hard",("case-study",),
             ("By utilizing a strongly consistent database state machine with optimistic locking on the order version", "By allowing drivers to write status updates directly to local memory variables", "By broadcasting order status changes via eventually consistent messaging channels", "By deleting and recreating the order record on every status transition"),0,
             "Optimistic locking (checking version before update) ensures only one driver can successfully transition an order to 'accepted'."),
        quiz("ubr-6","Which technology is best for pushing real-time order tracking updates to the customer's phone?","medium",("case-study",),
             ("Server-Sent Events (SSE) or WebSockets for live low-latency unidirectional coordinate updates", "A relational database trigger that updates the customer's local browser cookies", "Sending repeated transactional email updates every time the driver moves 10 meters", "Running background SMS query pings to locate the client device"),0,
             "SSE or WebSockets maintain persistent connections, enabling high-frequency location updates to the client app with minimal overhead."),
        quiz("ubr-7","How do you handle driver location tracking at scale (e.g., 500,000 drivers updating GPS every 3 seconds)?","hard",("case-study",),
             ("Route all pings through a distributed consensus group like ZooKeeper to ensure order", "Buffer location updates in a fast in-memory store like Redis, then periodically persist or drop historical traces", "Enforce clients to poll drivers directly via peer-to-peer web connections", "Write all raw location pings directly to a relational database primary write replica"),1,
             "Redis handles hundreds of thousands of writes/sec with ease. Storing temporary coordinate points in memory protects relational DBs."),
        quiz("ubr-8","What is the role of an Order Matching Engine in a delivery app?","hard",("case-study",),
             ("To run static SQL queries that calculate daily sales tax values", "To match orders with available drivers based on proximity, route efficiency, and wait times", "To generate restaurant menu recommendations using deep learning algorithms", "To encrypt credit card payment information during checkout"),1,
             "The matching engine coordinates complex operations: finding the best driver, projecting route paths, and assigning the task."),
        quiz("ubr-9","How do you handle 'dual-write' issues where the Order DB and Payment Service must both be updated?","hard",("case-study",),
             ("Use the Outbox Pattern or a Two-Phase Commit (2PC) to guarantee atomic database updates and event publishing", "Execute database updates only, and rely on users to manually report missing payments", "Perform both updates in parallel without error handling, assuming networks are 100% reliable", "Avoid updating the database and store transaction records solely in the gateway cache"),0,
             "The Outbox pattern writes events to an internal DB table in the same transaction, ensuring reliable publishing to message brokers."),
        quiz("ubr-10","What is the best way to handle restaurant menu caching?","medium",("case-study",),
             ("Cache menu data with a long TTL (e.g. 24 hours) since menus change infrequently, with explicit invalidation on updates", "Never cache menus to ensure users always see real-time price updates from the database", "Use a write-behind strategy to flush menu changes to the DB after 7 days", "Cache menus on client devices only without server-side backups"),0,
             "Menus are highly static. Caching them reduces load on the primary DB, while an invalidation trigger handles rare changes."),
        quiz("ubr-11","How can you partition/shard driver location data to scale horizontally?","hard",("case-study",),
             ("Shard location data by city or region code to keep queries local to the region", "Shard location data by the timestamp of the GPS update packet", "Store all coordinates in a single monolithic table without partitioning", "Shard data by the driver's unique sequential ID to ensure alphabetical balance"),0,
             "Queries (e.g., 'find nearby drivers') are strictly localized. Sharding by city keeps geographic data co-located on a single node."),
        quiz("ubr-12","If a restaurant's order queue grows too long, how should the system handle incoming customer requests?","medium",("case-study",),
             ("Route all excess orders to alternative random restaurants automatically", "Block customers from opening the restaurant page entirely", "Implement back-pressure or show dynamic delivery delay estimates based on restaurant queue depth", "Store excess orders in an infinite queue that never returns a response timeout"),2,
             "Dynamic ETAs and queue warnings adjust client expectations and prevent ordering bottlenecks during peak hours."),
        quiz("ubr-13","What is the primary trade-off of a short Geohash length (e.g., 4 characters)?","medium",("case-study",),
             ("It is computationally too slow to calculate on modern hardware", "It cannot be cached in Redis memory keys", "It represents a very large area (approx 39km x 20km), containing too many irrelevant restaurants", "It requires advanced relational database triggers to resolve"),2,
             "Short geohashes represent massive regions. Long geohashes represent tiny regions. Proximity searches must balance geohash length."),
        quiz("ubr-14","What is the purpose of using Dijkstra's or A* algorithm in this system?","easy",("case-study",),
             ("To balance HTTP server load across distributed worker nodes", "To compress coordinate data packets sent to mobile client devices", "To estimate delivery route paths, travel distances, and expected travel times", "To encrypt transaction payloads before routing them to the bank"),2,
             "Graph routing algorithms calculate optimal road network paths rather than simple straight-line 'as-the-crow-flies' distances."),
        quiz("ubr-15","How do you prevent driver GPS updates from overloading the API gateway?","medium",("case-study",),
             ("Block all updates while the driver is driving at speeds over 10 mph", "Deploy physical load balancers on every delivery vehicle in the fleet", "Use UDP instead of TCP, or implement client-side adaptive throttling based on whether the driver is moving", "Enforce the driver's phone to reboot every 15 minutes to clear network buffers"),2,
             "If driver is stationary, throttle updates (e.g., every 30s). When moving, increase updates. Saves server load and client battery."),
        quiz("ubr-16","Which database is best for storing historical order details for long-term tax and accounting reports?","medium",("case-study",),
             ("A graph database specialized in relationship mapping", "An in-memory Redis cache with high-frequency snapshotting", "An OLAP column-store database (like ClickHouse or Snowflake) for massive aggregations and analytics", "A local SQLite instance stored on the restaurant's tablets"),2,
             "OLAP databases are highly optimized for fast aggregation queries over billions of historical records."),
        quiz("ubr-17","How should the order dispatch system react if a driver loses cell connection mid-delivery?","hard",("case-study",),
             ("Delete the driver's history and ban their device from the platform", "Detect missing heartbeats, temporarily flag driver as offline, and trigger fallback assignment if necessary", "Block all other deliveries in the system until the driver reconnects", "Immediately cancel the order and issue a full refund to the customer"),1,
             "Heartbeat detection allows the matching engine to flag inactive drivers and safely re-route orders without leaving customers stranded."),
        quiz("ubr-18","What is the benefit of a Saga pattern in a local delivery architecture?","hard",("case-study",),
             ("It secures customer passwords using distributed hashing protocols", "It accelerates local SSD read performance during database migrations", "It automatically scales web socket connections based on system CPU load", "It coordinates multi-service transactions (Order -> Payment -> Restaurant Accept) with compensating transactions on failure"),3,
             "A Saga is a sequence of local transactions. If one step fails (e.g. restaurant rejects), Saga executes rollback/compensation steps."),
        quiz("ubr-19","How does Yelp/DoorDash handle geohash boundary issues (where a restaurant is just across the border of a geohash box)?","hard",("case-study",),
             ("By shifting coordinates dynamically until they land in the center of the geohash", "By querying the target geohash AND its 8 adjacent neighbor geohash boxes", "By blocking users from searching within 100 meters of quadrant boundaries", "By scaling the geohash box dynamically until it contains at least 50 results"),1,
             "Border issues are resolved by fetching the target box plus its 8 surrounding neighbors, ensuring no nearby restaurant is missed."),
        quiz("ubr-20","What type of index is highly optimized for geospatial operations in PostgreSQL?","medium",("case-study",),
             ("Standard BTREE indexes on coordinate columns", "GiST indexes using the PostGIS extension", "Hash indexes designed for exact match coordinate pairs", "Inverted GIN indexes built on JSON coordinate arrays"),1,
             "PostgreSQL with PostGIS uses GiST (Generalized Search Tree) indexes to accelerate geometric/geospatial queries."),
    ))

def robinhood_lesson() -> Lesson:
    return Lesson(id="hld-robinhood", number=219, title="Robinhood (Stock Trading)",
        focus=("real-time stock","order matching","concurrency locks","ACID ledger","SSE streaming"),
        overview="Design a highly reliable, low-latency real-time stock trading and matching platform like Robinhood.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("rob-1","How does Robinhood stream real-time stock price tickers to millions of concurrent user screens?","medium",("case-study",),
             ("Write stock price updates directly to a global relational database table with no caching", "Establish persistent Server-Sent Events (SSE) or WebSockets connections to client devices from a fast, cached market feed service", "Send daily email stock price digests to registered users", "Force client browsers to send HTTP GET requests for pricing every 100 milliseconds"),1,
             "SSE or WebSockets support low-latency real-time data streaming, pushing stock price movements to devices instantly with minimal network overhead."),
        quiz("rob-2","Which database transaction property is absolutely critical when executing a stock purchase?","hard",("case-study",),
             ("High database latency tolerance to buffer transactions", "ACID (Atomicity, Consistency, Isolation, Durability) to ensure ledger balance updates and stock allocations are perfectly secure", "Eventual consistency to maximize database write throughput", "NoSQL schema flexibility to store varying stock descriptors"),1,
             "Stock trades involve financial transactions. ACID guarantees that balance deduction and asset allocation both succeed or both fail together."),
        quiz("rob-3","What is the role of an Order Matching Engine in Robinhood?","hard",("case-study",),
             ("To index full-text search keywords for fast stock ticker queries", "To maintain a buy/sell limit order book and match trades in microseconds using a fast, in-memory data structure (e.g. FIFO/Price-Time)", "To encrypt payment card details during checkouts", "To balance HTTP gateway requests across distributed web servers"),1,
             "The matching engine runs in memory (often written in C++/Java or using LMAX Disruptor) to cross buy and sell orders at lightning speeds."),
        quiz("rob-4","How do you handle 'race conditions' if multiple concurrent users try to buy the last available shares of a hot stock?","hard",("case-study",),
             ("Allow all buy orders to succeed and resolve stock deficits manually later", "Use optimistic locking (version column) or explicit pessimistic database locks (SELECT FOR UPDATE) on the inventory balance row", "Store the stock share inventory in temporary in-memory caches that expire in 24 hours", "Route all orders through an eventually consistent messaging queue without synchronization"),1,
             "Pessimistic or optimistic locking prevents double-selling shares by ensuring each transaction verifies current balance availability before commit."),
        quiz("rob-5","What is a major advantage of the Saga pattern in a distributed stock trading architecture?","hard",("case-study",),
             ("It secures customer passwords using distributed hashing protocols", "It automatically scales web socket connections based on system CPU load", "It coordinates multi-service transactions (Deduct Cash -> Buy Stock -> Update Portfolio) with compensating rollbacks on failure", "It accelerates local SSD read performance during database migrations"),2,
             "A Saga guarantees reliability across distributed microservices: if the Brokerage declines the trade, Saga issues a cash refund transaction."),
        quiz("rob-6","Why is a Double-Entry Ledger database pattern required for Robinhood's accounting?","hard",("case-study",),
             ("It replaces the database for long-term historical transaction backups", "It encrypts all transactional details using separate public keys", "It doubles the processing speed of financial transactions", "It guarantees that money is never created or destroyed: every financial transaction consists of equal debit and credit records"),3,
             "Double-entry bookkeeping is the compliance and security standard, ensuring all system balances are fully auditable and structurally sound."),
        quiz("rob-7","What is the purpose of idempotency keys in stock order placement APIs?","hard",("case-study",),
             ("To encrypt transaction payloads during transport layer security (TLS) handshakes", "To index stock ticker columns inside the relational database", "To prevent duplicate stock purchases if a user double-clicks the 'Submit' button or retries a failed network call", "To verify the physical location of the buyer's IP address"),2,
             "An idempotency key (e.g. UUID) ensures the order placement pipeline processes a specific trade request exactly once, returning cached response on retries."),
        quiz("rob-8","How does the system scale during extreme market volatility (e.g., GameStop short squeeze surges)?","medium",("case-study",),
             ("By scaling relational database write instances to 1,000 nodes vertically", "By allowing double bookings and sorting out trades manually later", "By caching the trading write API endpoint globally on CDNs", "By using a high-throughput messaging queue (like Kafka) to buffer incoming orders, shielding the matching engine from crashes"),3,
             "Kafka queueing absorbs traffic spikes, protecting downstream transactional systems from crashing under unexpected trade volumes."),
        quiz("rob-9","What type of database index optimizes looking up all historical trades for a user sorted by date?","easy",("case-study",),
             ("A single index on the stock ticker string", "A hash index built on the user's password hash column", "A partial index built only on trades containing option contracts", "A composite index on (user_id, transaction_time DESC)"),3,
             "A composite index on (user_id, transaction_time DESC) allows the database to instantly retrieve and render the user's trade history."),
        quiz("rob-10","Why is an in-memory cache (like Redis) excellent for storing stock price ticker history for sparkline charts?","medium",("case-study",),
             ("It eliminates the need for maintaining relational database backups", "It automatically translates stock names into multiple languages", "It can be hosted inside the client's local smartphone OS environment", "It stores historical stock points in high-speed memory structures (Redis Lists or Streams) for ultra-fast chart renders"),3,
             "Serving sparkline coordinates (last 24 hours of price points) from Redis bypasses hitting the primary transactional database entirely."),
        quiz("rob-11","What is the role of an asynchronous worker pool in Robinhood's trade settlement?","medium",("case-study",),
             ("To run real-time stock price evaluations during database lock phases", "To execute clearing, clearing house reporting, tax logs, and email confirmations off the high-speed trade path", "To balance HTTP gateway requests across active web servers", "To encrypt credit card details inside the user's browser"),1,
             "Asynchronous workers offload slow compliance and logging pipelines from the core order matching flow, keeping trade confirmations fast."),
        quiz("rob-12","Which mechanism handles gateway node crashes gracefully during order processing?","hard",("case-study",),
             ("Message queues with acknowledgment (ACK) flows — if a worker dies, the un-ACKed trade is automatically returned to the queue", "Ignore the crash and show the user an eternal 'Pending' state", "Force the client browser to detect gateway failure and execute the trade locally", "Reboot the entire active server cluster automatically"),0,
             "Using message acknowledgment guarantees that no order is lost. If a node crashes, the broker detects the closed channel and re-queues the message."),
        quiz("rob-13","What type of database is highly optimized for storing historical trade logs for long-term audits and tax compliance?","medium",("case-study",),
             ("An OLAP column-store database (like ClickHouse or Snowflake) for massive aggregations and analytics", "A local SQLite instance stored on the client device", "An in-memory Redis cache with high-frequency snapshotting", "A graph database specialized in relationship mapping"),0,
             "OLAP databases are highly optimized for fast aggregation queries over billions of historical trade records."),
        quiz("rob-14","What is the advantage of using a dedicated search service for finding stock tickers (e.g. searching 'AAPL')?","medium",("case-study",),
             ("It automatically encrypts the search query string", "It provides fast, scalable full-text indexing, fuzzy matching, and synonym search across company listings", "It replaces the database for storing user balance ledgers", "It runs trade matching calculations faster"),1,
             "Elasticsearch provides near-instant lookup of stock symbols and company descriptions with typo tolerance, ensuring a smooth search UX."),
        quiz("rob-15","What index optimizes looking up all active alerts for a stock ticker when a new price point arrives?","hard",("case-study",),
             ("A single index on the user's password hash column", "A partial index built only on alerts that have expired", "A hash index built on the company name", "A composite index on (ticker, threshold_price)"),3,
             "A composite index on (ticker, threshold_price) allows the alerting service to instantly query and identify users whose stock thresholds were met."),
        quiz("rob-16","What is the benefit of a WebSockets connection over HTTP short polling for stock price tickers?","medium",("case-study",),
             ("WebSockets do not require SSL/TLS encryption protocols", "WebSockets reduce server connection overhead by avoiding repeated HTTP handshakes, header transmission, and DB checks", "WebSockets execute trades faster because they bypass compile steps", "WebSockets store trade results directly in the client's RAM memory"),1,
             "WebSockets support highly efficient, single-connection real-time push, avoiding the network waste of 10 rapid HTTP polls per user."),
        quiz("rob-17","How does the system ensure compliance with trade wash constraints (preventing users from trading with themselves)?","hard",("case-study",),
             ("It encrypts the order book so users cannot see their own orders", "It deletes the user's account if a wash trade is detected after transaction completion", "It requires all trades to be manually reviewed by a compliance officer", "The order matching engine verifies that the buy order and sell order do not originate from the same user account before matching"),3,
             "Enforcing check rules directly inside the matching engine prevents regulatory violations (wash trading) from being committed to the ledger."),
        quiz("rob-18","What is the primary trade-off of pre-computing user stock alerts?","medium",("case-study",),
             ("It prevents users from editing their alert settings after creation", "It requires using symmetric encryption keys for every single alert summary", "It works only on mobile device frameworks, not desktop web browsers", "It saves massive read latency on alert checks but consumes significant storage and write compute power"),3,
             "Pre-computing alert indexes is fast but means managing dynamic indexing maps for millions of active user thresholds."),
        quiz("rob-19","What type of locking is most appropriate when updating a user's cash balance?","medium",("case-study",),
             ("Pessimistic locking (SELECT FOR UPDATE) to block concurrent writes and ensure zero risk of balance overdrafts",
              "Optimistic locking (version numbers) since balance updates are highly contested by multiple active brokers",
              "Distributed Redlock across all active global application servers",
              "Enforcing a database-wide table lock on the ledger table"),0,
             "Cash balances are highly sensitive and can have concurrent settlement updates. Pessimistic locking guarantees 100% accurate, serialized balance writes."),
        quiz("rob-20","What index optimizes looking up all trades for a stock ticker within a specific hour?","hard",("case-study",),
             ("A single index on the user's password hash column", "A composite index on (ticker, transaction_time)", "A partial index built only on trades containing option contracts", "A hash index built on the company name"),1,
             "A composite index on (ticker, transaction_time) allows the analytics engine to fetch and count the stock's trades within a specific hour instantly."),
    ))

